import{_ as t,o,c as s,a2 as i}from"./chunks/framework.BWuWLRhz.js";const u=JSON.parse('{"title":"iOS PWA inspection findings","description":"","frontmatter":{},"headers":[],"relativePath":"adhoc/ios-pwa-inspection-findings.md","filePath":"adhoc/ios-pwa-inspection-findings.md"}'),a={name:"adhoc/ios-pwa-inspection-findings.md"};function n(r,e,d,c,l,h){return o(),s("div",null,[...e[0]||(e[0]=[i(`<h1 id="ios-pwa-inspection-findings" tabindex="-1">iOS PWA inspection findings <a class="header-anchor" href="#ios-pwa-inspection-findings" aria-label="Permalink to &quot;iOS PWA inspection findings&quot;">​</a></h1><p><strong>Status: ✅ Complete — all 5 findings resolved (2026-07-02).</strong> See the resolution table below. Remaining follow-up is production-build / on-device verification only (service worker and home-screen launch behaviour can&#39;t be exercised in dev).</p><p><strong>Date:</strong> 2026-07-02 <strong>Instance tested:</strong> local dev server (<code>pnpm dev</code>, runtime on <code>:3000</code>) exposed via ngrok, i.e. the same build an iPhone reaches through the tunnel. <strong>Method:</strong> emulated iPhone viewport (390×844, DPR 2) in a Chromium-based inspector; light and dark color schemes; full user flows exercised — sign-up → home → Apps drawer → Search overlay → Tasks plugin (list creation) → account menu → sign-out → sign-in. PWA plumbing (manifest, icons, meta tags, service worker, CSP) inspected directly; iOS-specific behavior (safe-area, viewport units, overscroll, focus zoom) verified against source.</p><p>No console errors or warnings were produced anywhere in the session.</p><p>Related: <a href="./../pwa-real-device-testing.html">pwa-real-device-testing.md</a> for on-device verification of anything fixed from this list.</p><hr><h2 id="resolution-status-updated-2026-07-02" tabindex="-1">Resolution status (updated 2026-07-02) <a class="header-anchor" href="#resolution-status-updated-2026-07-02" aria-label="Permalink to &quot;Resolution status (updated 2026-07-02)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>#</th><th>Issue</th><th>Status</th><th>Where the fix lives</th></tr></thead><tbody><tr><td>1</td><td>Input focus-zoom</td><td><strong>Fixed</strong></td><td><code>packages/ui</code> — Input + Select (<code>@sovereignfs/ui</code> 0.22.1)</td></tr><tr><td>2</td><td>Static dark <code>theme-color</code></td><td><strong>Fixed</strong></td><td><code>runtime/src/theme-script.ts</code>, <code>runtime/app/layout.tsx</code>, <code>plugins/account</code> ThemeControl</td></tr><tr><td>3</td><td>Tasks sidebar stale after create</td><td><strong>Fixed</strong></td><td><code>sovereign-tasks</code> plugin repo (<code>ListSidebar.tsx</code>) — separate repo, needs its own commit</td></tr><tr><td>4</td><td><code>/login</code> shown to authed users</td><td><strong>Fixed</strong></td><td><code>runtime/src/server-session.ts</code> + login/register pages</td></tr><tr><td>5</td><td>Missing iOS splash images</td><td><strong>Fixed</strong></td><td><code>scripts/generate-splash.ts</code> → <code>runtime/public/icons/splash/</code> + <code>runtime/src/apple-splash.ts</code>, wired in layout</td></tr></tbody></table><p>Verification was done against the running dev instance (emulated 390×844): single authoritative <code>theme-color</code> meta that flips light/dark and survives soft navigation; <code>/login</code> and <code>/register</code> redirect an authenticated visitor to <code>/</code>; the Tasks sidebar shows a newly created list without a reload; 84 <code>apple-touch-startup-image</code> links render in <code>&lt;head&gt;</code> with correct light/dark media queries and the images resolve (200). The input-zoom CSS rule ships for both Input and Select (<code>@media (pointer: coarse)</code> → 16px) — confirmed present in the served CSS; the emulator reports a fine pointer, so the final proof is an on-device tap-without-zoom per <a href="./../pwa-real-device-testing.html">pwa-real-device-testing.md</a>.</p><p>Caveat carried over from testing: the service worker is disabled in dev, so offline/caching and the installed-PWA launch experience (splash shows only on a real home-screen install) still need a production-build / on-device verification.</p><hr><h2 id="issues" tabindex="-1">Issues <a class="header-anchor" href="#issues" aria-label="Permalink to &quot;Issues&quot;">​</a></h2><h3 id="_1-text-inputs-trigger-ios-focus-zoom-—-highest-user-impact" tabindex="-1">1. Text inputs trigger iOS focus-zoom — highest user impact <a class="header-anchor" href="#_1-text-inputs-trigger-ios-focus-zoom-—-highest-user-impact" aria-label="Permalink to &quot;1. Text inputs trigger iOS focus-zoom — highest user impact&quot;">​</a></h3><p><strong>Symptom.</strong> Tapping any text field on an iPhone (Safari tab <em>and</em> installed PWA) zooms the whole page in. Affects every field in the product: login email/password, register form, home &quot;Search apps&quot;, Tasks &quot;Add a task…&quot;.</p><p><strong>Root cause.</strong> iOS Safari auto-zooms when a focused input&#39;s font-size is below 16px. The shared <code>Input</code> component renders at 14px — <code>packages/ui/src/components/Input/Input.module.css</code> line 6 sets <code>font-size: var(--sv-font-size-sm)</code>, and <code>--sv-font-size-sm</code> is <code>0.875rem</code> (14px) in <code>packages/ui/src/tokens/primitives.css</code>. The viewport meta (correctly) does not set <code>maximum-scale</code>, so nothing suppresses the zoom.</p><p><strong>Fix.</strong> Bump the effective input font-size to ≥16px on touch devices inside the <code>Input</code> component CSS, e.g.:</p><div class="language-css vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">@media</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (pointer: coarse) {</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">  .input</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    font-size</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">var</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">--sv-font-size-md</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">); </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">/* 16px — prevents iOS focus zoom */</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>Do <strong>not</strong> fix this by adding <code>maximum-scale=1</code> / <code>user-scalable=no</code> to the viewport meta — that suppresses pinch-zoom for low-vision users (accessibility regression) and only masks the cause.</p><p>Note <code>packages/ui</code> is a published design-system contract: this is a visual change to a public component, so it needs a Storybook check and a version bump per NFR-04 rules (non-breaking → patch/minor).</p><hr><h3 id="_2-theme-color-is-hard-coded-dark-while-the-app-supports-light-mode" tabindex="-1">2. <code>theme-color</code> is hard-coded dark while the app supports light mode <a class="header-anchor" href="#_2-theme-color-is-hard-coded-dark-while-the-app-supports-light-mode" aria-label="Permalink to &quot;2. \`theme-color\` is hard-coded dark while the app supports light mode&quot;">​</a></h3><p><strong>Symptom.</strong> In light mode, browser/OS chrome (Safari tab bar tint, Android status bar) renders near-black around a white UI. On Android, a light-mode install still gets a dark splash screen.</p><p><strong>Root cause.</strong> Two places declare dark-only colors:</p><ul><li><code>runtime/app/layout.tsx</code> line 40: static <code>themeColor: &#39;#09090b&#39;</code> in the Next metadata export.</li><li><code>runtime/app/api/manifest/route.ts</code> lines 35–36: <code>background_color: &#39;#09090b&#39;</code>, <code>theme_color: &#39;#09090b&#39;</code>. The manifest <code>background_color</code> drives the Android splash; <code>theme_color</code> tints Android system UI.</li></ul><p>The app itself resolves <code>data-theme=&quot;light&quot; | &quot;dark&quot;</code> at runtime, so the static value is wrong half the time.</p><p><strong>Fix.</strong> Next metadata supports media-qualified theme colors — replace the static value with:</p><div class="language-ts vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">themeColor</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  { media: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;(prefers-color-scheme: light)&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, color: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;&lt;light surface token value&gt;&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  { media: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;(prefers-color-scheme: dark)&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, color: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;#09090b&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">],</span></span></code></pre></div><p>Use the light-mode <code>--sv-color-surface</code> value for the light entry. The manifest cannot be media-qualified (single value per spec); either keep it dark as the lesser evil, or pick based on a future instance-theme setting when CON-08 theming lands. If the user&#39;s theme preference is stored server-side, <code>/api/manifest</code> could read it — but manifests are cached aggressively, so don&#39;t rely on it being fresh.</p><p>Caveat: if the in-app theme toggle can diverge from the OS scheme (user forces light while OS is dark), the media-query approach follows the OS, not the app. Full correctness requires swapping the <code>&lt;meta name=&quot;theme-color&quot;&gt;</code> value from the theme-switch code path as well.</p><p><strong>Implemented (diverged from the above).</strong> The media-qualified <code>viewport.themeColor</code> approach was tried and abandoned: Next&#39;s metadata reconciler re-inserts its own copy during hydration, so a server-rendered meta ends up <strong>duplicated</strong> and the browser honours the last one. The shipped fix instead removes <code>themeColor</code> from the <code>viewport</code> export entirely and lets the pre-paint theme script own a single <code>theme-color</code> meta (create-or-update to <code>#ffffff</code>/<code>#09090b</code>), with <code>plugins/account</code> <code>ThemeControl</code> updating it on live toggle. This also handles the cookie-driven light/dark override that a media query can&#39;t. Editing the pinned theme script required recomputing <code>THEME_SCRIPT_CSP_HASH</code> in <code>runtime/src/security.ts</code>. The manifest route&#39;s <code>theme_color</code>/<code>background_color</code> were left dark (single-value, not media-qualifiable).</p><hr><h3 id="_3-tasks-plugin-sidebar-does-not-refresh-after-creating-a-list" tabindex="-1">3. Tasks plugin: sidebar does not refresh after creating a list <a class="header-anchor" href="#_3-tasks-plugin-sidebar-does-not-refresh-after-creating-a-list" aria-label="Permalink to &quot;3. Tasks plugin: sidebar does not refresh after creating a list&quot;">​</a></h3><p><strong>Symptom.</strong> Creating a list via &quot;+&quot; → name → Enter opens the new list in the detail pane, but the &quot;MY LISTS&quot; sidebar still shows &quot;No lists yet. Create one above.&quot; The new list only appears after a full page reload.</p><p><strong>Root cause.</strong> State-sync bug in the tasks plugin: the create action updates whatever state drives the detail pane but never updates (or revalidates) the collection behind the sidebar list. Sidebar component: <code>plugins/sovereign-tasks.local/app/ListSidebar.tsx</code>. Reproduced on the running instance; the exact wiring (local state vs. server revalidation) should be confirmed in the plugin repo — the fix belongs there, not in this monorepo.</p><p><strong>Fix.</strong> After a successful create, either update the shared client state that the sidebar renders from, or trigger the same refetch/<code>router.refresh()</code>/revalidation path the sidebar uses on first load. A reload-shaped fix (full navigation) would also mask it but is the wrong tool.</p><p><strong>Related copy nit (mobile).</strong> The empty states say &quot;Create one above&quot; and &quot;Choose a list from the sidebar&quot;. On the stacked mobile layout there is no visible &quot;sidebar&quot; and the create control is a small &quot;+&quot; in the same row — the copy reads wrong on a phone. Per naming conventions, user-facing copy tweaks here should keep &quot;app&quot; terminology if any is added.</p><hr><h3 id="_4-login-renders-the-sign-in-form-for-already-authenticated-users" tabindex="-1">4. <code>/login</code> renders the sign-in form for already-authenticated users <a class="header-anchor" href="#_4-login-renders-the-sign-in-form-for-already-authenticated-users" aria-label="Permalink to &quot;4. \`/login\` renders the sign-in form for already-authenticated users&quot;">​</a></h3><p><strong>Symptom.</strong> With a valid session, navigating to <code>/login</code> shows the sign-in form instead of redirecting to <code>/</code>.</p><p><strong>Why it matters for iOS PWA.</strong> Standalone apps restore their last URL on relaunch. A user whose app last sat on <code>/login</code> (e.g. after a previous sign-out) relaunches into a login form even though their session is valid — they either sign in redundantly or get confused.</p><p><strong>Root cause.</strong> The middleware guards protected routes (redirects unauthenticated → <code>/login</code>) but has no inverse rule: <code>/login</code>, <code>/register</code>, and the other public auth pages don&#39;t check for an existing session. Verified live: with a valid session cookie, <code>GET /</code> returns 200 while <code>GET /login</code> serves the form.</p><p><strong>Fix.</strong> In <code>runtime/middleware.ts</code> (or in the login page&#39;s server component), when the session cookie verifies for a request to <code>/login</code> or <code>/register</code>, 303-redirect to <code>/</code>. Reuse the existing offline cookie-cache verification so this adds no auth-server round-trip on the hot path. Keep <code>/login?signedout=1</code> behavior intact — that arrives cookie-less after logout, so it is unaffected.</p><hr><h3 id="_5-no-ios-splash-screens-apple-touch-startup-image" tabindex="-1">5. No iOS splash screens (<code>apple-touch-startup-image</code>) <a class="header-anchor" href="#_5-no-ios-splash-screens-apple-touch-startup-image" aria-label="Permalink to &quot;5. No iOS splash screens (\`apple-touch-startup-image\`)&quot;">​</a></h3><p><strong>Symptom.</strong> Cold-launching the installed PWA on an iPhone shows a blank white flash before the app paints — jarring against a dark theme.</p><p><strong>Root cause.</strong> The document head contains zero <code>&lt;link rel=&quot;apple-touch-startup-image&quot;&gt;</code> entries. iOS ignores the manifest&#39;s <code>background_color</code>/icons for launch screens; it only honors these Apple-specific links, and it requires exact per-device-resolution images (each device picks the link whose media query matches its screen).</p><p><strong>Fix (implemented).</strong> Added <code>scripts/generate-splash.ts</code> (<code>pnpm generate:splash</code>), which uses <code>sharp</code> (a devDependency — nothing native is needed at build/runtime since the PNGs are committed) to composite the brand mark (<code>favicon.svg</code>) onto the light/dark surface colours for a comprehensive Apple device matrix (21 devices × portrait/landscape × light/dark = 84 PNGs, palette-compressed to ~0.8 MB total). Output goes to <code>runtime/public/icons/splash/</code>, and the script also emits <code>runtime/src/apple-splash.ts</code> — the <code>{ url, media }</code> list consumed by <code>metadata.appleWebApp.startupImage</code> in <code>runtime/app/layout.tsx</code>. Each device gets both a <code>(prefers-color-scheme: light)</code> and <code>(prefers-color-scheme: dark)</code> link. Regenerate (e.g. when Apple ships new screen sizes) by appending to the <code>DEVICES</code> array and re-running. The PNGs ship via <code>runtime/public</code> (already <code>COPY</code>d in the Dockerfile), so no Docker change is required.</p><hr><h2 id="testing-caveats-not-bugs" tabindex="-1">Testing caveats (not bugs) <a class="header-anchor" href="#testing-caveats-not-bugs" aria-label="Permalink to &quot;Testing caveats (not bugs)&quot;">​</a></h2><ul><li><strong>No service worker on the dev/ngrok instance.</strong> <code>/sw.js</code> is 404 because next-pwa is disabled in development (<code>runtime/next.config.ts</code> line 54, by design). Everything tested through the ngrok tunnel therefore has <strong>no offline support and no caching</strong>, and the <code>/offline</code> page (which exists and renders fine) is unreachable organically. Offline behavior, install-update cycles, and caching must be verified against a production build (<code>pnpm build</code> / Docker). See <a href="./../pwa-real-device-testing.html">pwa-real-device-testing.md</a>.</li><li>Next.js emits <code>mobile-web-app-capable</code> but not the legacy <code>apple-mobile-web-app-capable</code> meta. Irrelevant on any iOS version that reads the web-app manifest (iOS 11.3+); informational only.</li><li>The account menu opens on <code>pointerdown</code> (Radix-style). Real taps are unaffected — only synthetic-click test tooling needs to send pointer events. Hit-testing on all controls resolved to the correct elements; no overlay/z-index problems.</li></ul><h2 id="verified-healthy" tabindex="-1">Verified healthy <a class="header-anchor" href="#verified-healthy" aria-label="Permalink to &quot;Verified healthy&quot;">​</a></h2><ul><li><strong>Manifest</strong> (<code>/api/manifest</code>): <code>display: standalone</code> (+ <code>display_override</code>), <code>scope: /</code>, <code>start_url: /</code>, shortcuts, valid icon set — 192/512 <code>any</code> + 512 <code>maskable</code>, all served 200 with correct intrinsic sizes; <code>apple-touch-icon</code> is a proper 180×180.</li><li><strong>Viewport &amp; safe areas:</strong> <code>viewport-fit=cover</code> present; <code>env(safe-area-inset-*)</code> handled in the shell header, mobile nav, mobile search, and the UI <code>Drawer</code>; <code>100dvh</code> with <code>100vh</code> fallback plus the <code>--sv-vh</code> stale-dvh workaround; overscroll containment on drawer/dialog/search surfaces.</li><li><strong>Auth stays same-origin end to end</strong> — login, register, and logout (<code>POST /api/account/logout</code> → 303 <code>/login?signedout=1</code>, with a visible signed-out notice) never leave the runtime origin, so the installed PWA never breaks out of standalone mode. Session is rejected immediately after logout (cache cookies cleared correctly).</li><li><strong>Layout:</strong> no horizontal overflow at 390px on any screen tested; Apps drawer and Search overlay render and behave correctly in both light and dark themes.</li><li><strong>CSP:</strong> nonce-based <code>script-src</code>, no <code>unsafe-inline</code> scripts; <code>form-action</code> includes the auth origin.</li></ul><h2 id="suggested-priority" tabindex="-1">Suggested priority <a class="header-anchor" href="#suggested-priority" aria-label="Permalink to &quot;Suggested priority&quot;">​</a></h2><table tabindex="0"><thead><tr><th>#</th><th>Issue</th><th>Priority</th><th>Where</th></tr></thead><tbody><tr><td>1</td><td>Input focus-zoom (14px inputs)</td><td>High — felt on every field, every day</td><td><code>packages/ui</code> Input</td></tr><tr><td>3</td><td>Tasks sidebar stale after create</td><td>High — core flow visibly broken</td><td>tasks plugin repo</td></tr><tr><td>2</td><td>Static dark <code>theme-color</code></td><td>Medium — cheap fix, visible chrome mismatch</td><td><code>runtime/app/layout.tsx</code>, manifest route</td></tr><tr><td>4</td><td><code>/login</code> shown to authed users</td><td>Low — relaunch edge case</td><td><code>runtime/middleware.ts</code></td></tr><tr><td>5</td><td>Missing iOS splash images</td><td>Low — polish</td><td><code>runtime/app/layout.tsx</code>, <code>runtime/public/icons/</code></td></tr></tbody></table>`,54)])])}const g=t(a,[["render",n]]);export{u as __pageData,g as default};
